const item = $json;

function safe(value) {
  return value === undefined || value === null || value === "" ? "-" : String(value).trim();
}

function normalizeKey(key) {
  return String(key)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[’']/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function getValue(possibleNames) {
  for (const name of possibleNames) {
    const foundKey = Object.keys(item).find(
      key => normalizeKey(key) === normalizeKey(name)
    );
    if (foundKey && safe(item[foundKey]) !== "-") {
      return item[foundKey];
    }
  }
  return "-";
}

function formatDate(value) {
  if (!value || value === "-") return "-";

  const raw = String(value).trim();

  if (/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(raw)) {
    return raw;
  }

  if (/^\d+(\.\d+)?$/.test(raw)) {
    const serial = Number(raw);
    const date = new Date((serial - 25569) * 86400 * 1000);
    const day = String(date.getUTCDate()).padStart(2, "0");
    const month = String(date.getUTCMonth() + 1).padStart(2, "0");
    const year = date.getUTCFullYear();
    return `${day}/${month}/${year}`;
  }

  const parsed = new Date(raw);
  if (!isNaN(parsed)) {
    const day = String(parsed.getDate()).padStart(2, "0");
    const month = String(parsed.getMonth() + 1).padStart(2, "0");
    const year = parsed.getFullYear();
    return `${day}/${month}/${year}`;
  }

  return raw;
}

function badge(value) {
  const v = safe(value);
  const n = normalizeKey(v);

  let cls = "badge neutral";
  if (n === "tres bien") cls = "badge excellent";
  if (n === "bon") cls = "badge good";
  if (n === "moyen") cls = "badge average";
  if (n === "mauvais") cls = "badge bad";
  if (n === "non applicable" || n === "n/a") cls = "badge na";

  if (["tres bien", "bon", "moyen", "mauvais", "non applicable", "n/a"].includes(n)) {
    return `<span class="${cls}">${v}</span>`;
  }

  return `<span class="text-value">${v}</span>`;
}

const locataire = safe(getValue(["Nom du locataire", "Locataire"]));
const bailleur = safe(getValue(["Nom du bailleur", "Bailleur"]));
const emailLocataire = safe(getValue(["Adresse email du locataire", "email_locataire", "Email locataire"]));
const adresseAppartement = safe(getValue(["Adresse de l’appartement", "Adresse de l'appartement", "Adresse"]));
const dateEtatRaw = getValue(["Date de l’état des lieux", "Date de l'etat des lieux", "Date"]);
const dateEtat = formatDate(dateEtatRaw);
const typeEtat = safe(getValue(["Type"]));

const excludedKeys = [
  "Timestamp",
  "Nom du locataire",
  "Locataire",
  "Nom du bailleur",
  "Bailleur",
  "Adresse email du locataire",
  "email_locataire",
  "Email locataire",
  "Adresse de l’appartement",
  "Adresse de l'appartement",
  "Adresse",
  "Date de l’état des lieux",
  "Date de l'etat des lieux",
  "Date",
  "Type",
  "Total",
  "Bon",
  "Moyen",
  "Mauvais",
  "N/A"
].map(normalizeKey);

const detailEntries = Object.entries(item).filter(([key, value]) => {
  const nk = normalizeKey(key);
  return !excludedKeys.includes(nk) && safe(value) !== "-";
});

const total = detailEntries.length;
const bon = detailEntries.filter(([_, v]) => normalizeKey(v) === "bon" || normalizeKey(v) === "tres bien").length;
const moyen = detailEntries.filter(([_, v]) => normalizeKey(v) === "moyen").length;
const mauvais = detailEntries.filter(([_, v]) => normalizeKey(v) === "mauvais").length;
const na = detailEntries.filter(([_, v]) => normalizeKey(v) === "non applicable" || normalizeKey(v) === "n/a").length;

const detailRows = detailEntries.map(([key, value]) => `
  <tr>
    <td class="element">${safe(key)}</td>
    <td class="etat">${badge(value)}</td>
  </tr>
`).join("");

